#' Generate a list of model events with listeners
#'
#' Listeners are arbitrary functions called when the event is fired. Their only
#' argument is the current time step.
#'
#' @param variables_list A list of the model variables as generated by [create_variables()]
#' @param parameters_list A list of model parameters as generated by [get_parameters()]
#'
#' @family events
#' @export
create_events <- function(variables_list, parameters_list) {
  # Open a list to store the model events and populate using the event generator functions:
  events_list <- list(
    # Event moving exposed individuals to the infectious state
    EI_mild_event = individual::TargetedEvent$new(
      population_size = parameters_list$human_population
    ),
    EIhosp_event = individual::TargetedEvent$new(
      population_size = parameters_list$human_population
    ),

    # Event moving exposed individuals to the infectious state
    I_mild_R_event = individual::TargetedEvent$new(
      population_size = parameters_list$human_population
    ),
    I_hosp_R_event = individual::TargetedEvent$new(
      population_size = parameters_list$human_population
    ),
    I_hosp_D_event = individual::TargetedEvent$new(
      population_size = parameters_list$human_population
    )
  )

  # Listener: E -> I_mild
  events_list$EI_mild_event$add_listener(
    function(t, target) {
      variables_list$disease_state$queue_update("I_mild", target)
    }
  )

  # Listener: E -> I_hosp
  events_list$EIhosp_event$add_listener(
    function(t, target) {
      variables_list$disease_state$queue_update("I_hosp", target)
    }
  )

  # Listener: I_mild -> R
  events_list$I_mild_R_event$add_listener(
    function(t, target) {
      variables_list$disease_state$queue_update("R", target)
    }
  )

  # Listener: I_hosp -> R
  events_list$I_hosp_R_event$add_listener(
    function(t, target) {
      variables_list$disease_state$queue_update("R", target)
    }
  )

  # Listener: I_hosp -> D
  events_list$I_hosp_D_event$add_listener(
    function(t, target) {
      variables_list$disease_state$queue_update("D", target)
    }
  )

  # Add RS_event and listener if endemic pathogen is required (i.e. individuals going R->S)
  if (parameters_list$endemic_or_epidemic == "endemic") {
    RS_event <- individual::TargetedEvent$new(
      population_size = parameters_list$human_population
    )
    events_list <- c(events_list, list(RS_event = RS_event))

    events_list$RS_event$add_listener(
      function(t, target) {
        variables_list$disease_state$queue_update("S", target)
      }
    )
  }

  # Return the list of model events:
  events_list
}
